mapper.select:
select interface_info_id, count(1) as bound_user_count, coalesce(sum(left_num), 0) as total_left_num, coalesce(sum(total_num), 0) as total_invoke_num from user_interface_info where is_delete = 0 and interface_info_id in
#{interfaceInfoId}
group by interface_info_id

select user_id, count(distinct interface_info_id) as bound_interface_count, coalesce(sum(left_num), 0) as total_left_num, coalesce(sum(total_num), 0) as total_invoke_num from user_interface_info where is_delete = 0 and user_id in
#{userId}
group by user_id

mapper.update:
update user_interface_info
set left_num = left_num + #{grantNum}
where id = #{id}
  and is_delete = 0

update user_interface_info
set left_num = left_num - #{revokeNum}
where id = #{id}
  and is_delete = 0
  and left_num >= #{revokeNum}

update user_interface_info
set status = #{status}
where user_id = #{userId}
  and interface_info_id = #{interfaceInfoId}
  and is_delete = 0

mapper.select:
select count(1) as total_binding_count, coalesce(sum(case when status = 0 then 1 else 0 end), 0) as enabled_binding_count, coalesce(sum(case when status = 1 then 1 else 0 end), 0) as disabled_binding_count, coalesce(sum(left_num), 0) as total_left_num, coalesce(sum(total_num), 0) as total_invoke_num, count(distinct user_id) as affected_user_count, count(distinct interface_info_id) as affected_interface_count from user_interface_info where is_delete = 0
and user_id = #{userId}
and interface_info_id = #{interfaceInfoId}
and status = #{status}
